import{_ as a,o as l,c as s,ag as e}from"./chunks/framework.CvgP6Fyv.js";const u=JSON.parse('{"title":"考察报告写作指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/writing-guide.md","filePath":"guide/writing-guide.md"}'),t={name:"guide/writing-guide.md"};function n(r,i,h,o,d,p){return l(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="考察报告写作指南" tabindex="-1">考察报告写作指南 <a class="header-anchor" href="#考察报告写作指南" aria-label="Permalink to &quot;考察报告写作指南&quot;">​</a></h1><h2 id="报告要求" tabindex="-1">报告要求 <a class="header-anchor" href="#报告要求" aria-label="Permalink to &quot;报告要求&quot;">​</a></h2><h3 id="主题选择" tabindex="-1">主题选择 <a class="header-anchor" href="#主题选择" aria-label="Permalink to &quot;主题选择&quot;">​</a></h3><p>选择 1-2 个专业主题进行深入分析，避免流水账式的全景记录。</p><p>参考方向：</p><ul><li>建筑语言融合与场所重构</li><li>材料表达与建造智慧</li><li>空间秩序与场所精神</li><li>遗产保护与活态传承</li><li>中西建筑文化的对话</li></ul><h3 id="结构建议" tabindex="-1">结构建议 <a class="header-anchor" href="#结构建议" aria-label="Permalink to &quot;结构建议&quot;">​</a></h3><ol><li><strong>引言</strong>：提出研究问题</li><li><strong>案例分析</strong>：选择能形成对比逻辑的案例</li><li><strong>专业视角</strong>：运用建筑史和保护理论</li><li><strong>批判性思考</strong>：不只是描述，要有反思</li><li><strong>结论</strong>：提炼理论观点</li></ol><h3 id="内容要求" tabindex="-1">内容要求 <a class="header-anchor" href="#内容要求" aria-label="Permalink to &quot;内容要求&quot;">​</a></h3><ul><li><strong>字数</strong>：2000字左右</li><li><strong>图片</strong>：不少于10张，包含现场照片和专业图纸</li><li><strong>逻辑</strong>：从现象到本质，从具体到抽象</li><li><strong>深度</strong>：体现建筑历史和文化遗产保护的专业性</li></ul><h2 id="图片处理" tabindex="-1">图片处理 <a class="header-anchor" href="#图片处理" aria-label="Permalink to &quot;图片处理&quot;">​</a></h2><h3 id="图片格式" tabindex="-1">图片格式 <a class="header-anchor" href="#图片格式" aria-label="Permalink to &quot;图片格式&quot;">​</a></h3><p>支持格式：</p><ul><li>JPG / JPEG（推荐用于照片）</li><li>PNG（推荐用于带透明背景的图）</li><li>GIF（动图）</li><li>SVG（矢量图）</li><li>WebP（现代格式）</li></ul><h3 id="图片优化" tabindex="-1">图片优化 <a class="header-anchor" href="#图片优化" aria-label="Permalink to &quot;图片优化&quot;">​</a></h3><p>建议尺寸：</p><ul><li>宽度：800-1200 像素</li><li>文件大小：建议小于 2MB</li><li>格式：JPG 75-85% 压缩质量</li></ul><p>工具推荐：</p><ul><li><a href="https://tinypng.com/" target="_blank" rel="noreferrer">TinyPNG</a> - 在线压缩</li><li><a href="https://squoosh.app/" target="_blank" rel="noreferrer">Squoosh</a> - Google 压缩工具</li><li>Photoshop 或 GIMP - 本地编辑</li></ul><h3 id="图片插入" tabindex="-1">图片插入 <a class="header-anchor" href="#图片插入" aria-label="Permalink to &quot;图片插入&quot;">​</a></h3><p>在 Markdown 中使用：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">![</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">图片说明</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">相对路径/图片文件名.jpg</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>示例：</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">![</span><span style="--shiki-light:#032F62;--shiki-light-text-decoration:underline;--shiki-dark:#DBEDFF;--shiki-dark-text-decoration:underline;">图1：立园泮立楼主立面</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">](</span><span style="--shiki-light:#24292E;--shiki-light-text-decoration:underline;--shiki-dark:#E1E4E8;--shiki-dark-text-decoration:underline;">./images/liyuan-1.jpg</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="协作流程" tabindex="-1">协作流程 <a class="header-anchor" href="#协作流程" aria-label="Permalink to &quot;协作流程&quot;">​</a></h2><h3 id="使用-github-协作" tabindex="-1">使用 GitHub 协作 <a class="header-anchor" href="#使用-github-协作" aria-label="Permalink to &quot;使用 GitHub 协作&quot;">​</a></h3><ol><li><p><strong>Fork 仓库</strong></p><ul><li>点击仓库右上角的 Fork 按钮</li><li>创建自己的副本</li></ul></li><li><p><strong>创建分支</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature/你的报告</span></span></code></pre></div></li><li><p><strong>提交更改</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;添加第X组考察报告&quot;</span></span></code></pre></div></li><li><p><strong>推送分支</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature/你的报告</span></span></code></pre></div></li><li><p><strong>创建 Pull Request</strong></p><ul><li>在 GitHub 上发起 PR</li><li>邀请队友和老师审核</li></ul></li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-如何确定报告主题" tabindex="-1">Q: 如何确定报告主题？ <a class="header-anchor" href="#q-如何确定报告主题" aria-label="Permalink to &quot;Q: 如何确定报告主题？&quot;">​</a></h3><p>A: 从以下角度思考：</p><ul><li>你最感兴趣的问题是什么？</li><li>哪些案例之间有对比性？</li><li>你能从哪个专业角度深入分析？</li></ul><h3 id="q-图片太多怎么办" tabindex="-1">Q: 图片太多怎么办？ <a class="header-anchor" href="#q-图片太多怎么办" aria-label="Permalink to &quot;Q: 图片太多怎么办？&quot;">​</a></h3><p>A: 精选原则：</p><ul><li>选择最能说明问题的图片</li><li>每个章节 2-3 张图片为宜</li><li>图文要紧密配合</li></ul><h3 id="q-如何提升专业性" tabindex="-1">Q: 如何提升专业性？ <a class="header-anchor" href="#q-如何提升专业性" aria-label="Permalink to &quot;Q: 如何提升专业性？&quot;">​</a></h3><p>A: 建议方法：</p><ul><li>引用专业理论和术语</li><li>绘制分析图和示意图</li><li>进行批判性思考</li><li>参考学术文献</li></ul><h3 id="q-报告如何修改" tabindex="-1">Q: 报告如何修改？ <a class="header-anchor" href="#q-报告如何修改" aria-label="Permalink to &quot;Q: 报告如何修改？&quot;">​</a></h3><p>A: 流程：</p><ol><li>创建新分支进行修改</li><li>提交 Pull Request</li><li>团队成员评论反馈</li><li>根据反馈修改</li><li>合并到主分支</li></ol><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><h3 id="理论文献" tabindex="-1">理论文献 <a class="header-anchor" href="#理论文献" aria-label="Permalink to &quot;理论文献&quot;">​</a></h3><ol><li>《开平碉楼》，广东省文物考古研究所，文物出版社</li><li>《华侨建筑文化研究》，华侨大学建筑学院</li><li>《文化遗产保护的理论与实践》，同济大学</li></ol><h3 id="网络资源" tabindex="-1">网络资源 <a class="header-anchor" href="#网络资源" aria-label="Permalink to &quot;网络资源&quot;">​</a></h3><ul><li><a href="https://whc.unesco.org/en/list/1112/" target="_blank" rel="noreferrer">UNESCO 开平碉楼</a></li><li><a href="http://www.kptour.com/" target="_blank" rel="noreferrer">开平碉楼官网</a></li><li><a href="http://www.ncha.gov.cn/" target="_blank" rel="noreferrer">中国文化遗产保护网</a></li></ul><hr><p><strong>祝你写作顺利！</strong></p>`,47)])])}const g=a(t,[["render",n]]);export{u as __pageData,g as default};
